                                    : (currRaw == Short.TYPE) ? Short.class
                                    : (currRaw == Character.TYPE) ? Character.class
                                    : (currRaw == Float.TYPE) ? Float.class
                                    : (currRaw == Double.TYPE) ? Double.class
                                    : null;
