                            Class<?> wrap = (serClass == Integer.TYPE) ? Integer.class
                                    : (serClass == Long.TYPE) ? Long.class
                                    : (serClass == Boolean.TYPE) ? Boolean.class
                                    : (serClass == Byte.TYPE) ? Byte.class
                                    : (serClass == Short.TYPE) ? Short.class
                                    : (serClass == Character.TYPE) ? Character.class
                                    : (serClass == Float.TYPE) ? Float.class
                                    : (serClass == Double.TYPE) ? Double.class
                                    : null;
                            ignore = (wrap != null) && (wrap == currRaw);
                        }
                        if (!ignore) {
                            throw new JsonMappingException(null,
                                    String.format("Can not refine serialization type %s into %s; types not related",
                                            type, serClass.getName()));
                        }
                    }
                } catch (IllegalArgumentException iae) {
                    throw new JsonMappingException(null,
                            String.format("Failed to widen type %s with annotation (value %s), from '%s': %s",
